#include <bits/stdc++.h>
using namespace std;
using ll = long long;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    ll N;
    cin >> N;

    // We need to find a representation N = a + (a+1) + ... + (a+k-1)
    // N = k * a + k*(k-1)/2  =>  N - k*(k-1)/2 = k * a
    // So for each k (number of terms), check if N - k*(k-1)/2 is divisible by k and >0
    // The maximum k is such that k*(k+1)/2 <= N (since smallest sum of k consecutive numbers starting from 1 is k(k+1)/2)
    // We iterate k from largest possible down to 1 to find the longest (since we need max k).
    // Actually we want max k. Start from maxK down to 1, first valid is max k.

    ll best_k = 1;
    ll best_a = N;

    // max k such that k*(k+1)/2 <= N
    ll max_k = 0;
    // Solve k^2 + k - 2N <= 0 => k <= (-1 + sqrt(1+8N))/2
    max_k = (ll)((sqrt(1.0L + 8.0L * N) - 1.0L) / 2.0L);

    for (ll k = max_k; k >= 1; --k) {
        ll num = N - k * (k - 1) / 2;
        if (num <= 0) continue;
        if (num % k == 0) {
            ll a = num / k;
            // a must be >= 1
            if (a >= 1) {
                best_k = k;
                best_a = a;
                break;
            }
        }
    }

    cout << best_a << " " << best_k << "\n";
    return 0;
}
